#!/usr/bin/env python3
import os
import re

def check_references(directory, pattern):
    """Check files for a pattern"""
    matches = []
    for root, dirs, files in os.walk(directory):
        # Skip git and other hidden directories
        dirs[:] = [d for d in dirs if not d.startswith('.')]

        for file in files:
            if file.endswith('.py'):
                filepath = os.path.join(root, file)
                try:
                    with open(filepath, 'r', encoding='utf-8', errors='ignore') as f:
                        for i, line in enumerate(f, 1):
                            if re.search(pattern, line):
                                matches.append((filepath.replace('/workspace/', ''), i, line.strip()))
                except:
                    pass
    return matches

# Check for old name
old_refs = check_references('/workspace/numpy', r'array_function_dispatch')
# Check for new name
new_refs = check_references('/workspace/numpy', r'dispatch_array_function')

print(f"Old name references found: {len(old_refs)}")
if old_refs:
    for path, line_num, content in old_refs[:5]:
        print(f"  {path}:{line_num}: {content[:60]}...")

print(f"\nNew name references found: {len(new_refs)}")
print(f"\nRename completeness: {100 if len(old_refs) == 0 else 'INCOMPLETE'}")
EOF
